BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Infective Endocarditis' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Infective Endocarditis', 'Valve infection, Duke criteria, embolic signs, treatment', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Infective Endocarditis (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Infective Endocarditis - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Definition in this patient with suspected valve infection?', 'Which finding most strongly supports Definition in this patient with suspected valve infection?', '[{"id": "a", "text": "Vegetations in this note are sterile in infective cases."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "Endocarditis is infection of the pericardium in this note."}, {"id": "d", "text": "Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms."}]'::jsonb, '["d"]'::jsonb, 'Correct because Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms. Treat suspected valve infection urgently to limit embolic and valvular destruction.', 'Infective Endocarditis - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Valve distribution?', 'The nurse reviews chart data; which interpretation best matches Valve distribution?', '[{"id": "a", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "b", "text": "Valve choice is random and unrelated to risk factors in this note."}, {"id": "c", "text": "This pattern is more consistent with PATHOGENS mnemonic."}, {"id": "d", "text": "Use risk profile to anticipate likely side/valve complications."}]'::jsonb, '["d"]'::jsonb, 'Correct because Mitral valve is commonly affected on the left side, and tricuspid involvement is common in IV drug use (right-sided). Use risk profile to anticipate likely side/valve complications.', 'Infective Endocarditis - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Organisms overview?', 'Which clinical judgment is most accurate regarding Organisms overview?', '[{"id": "a", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "b", "text": "Common organisms include Streptococcus viridans, Staphylococcus aureus, Enterococcus, S. epidermidis on prosthetic valves, and HACEK organisms."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Only viral organisms cause infective endocarditis in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Common organisms include Streptococcus viridans, Staphylococcus aureus, Enterococcus, S. epidermidis on prosthetic valves, and HACEK organisms. Start broad directed therapy and narrow with culture data.', 'Infective Endocarditis - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Non-infective forms?', 'In rapid prioritization, which conclusion aligns best with Non-infective forms?', '[{"id": "a", "text": "Libman-Sacks is caused by S. aureus in this note."}, {"id": "b", "text": "Differentiate sterile vegetations from true infection before prolonged antimicrobials."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "This pattern is more consistent with Janeway lesions."}]'::jsonb, '["b"]'::jsonb, 'Correct because Non-infective endocarditis includes marantic (cancer/wasting) and Libman-Sacks (SLE), where vegetations have no organisms. Differentiate sterile vegetations from true infection before prolonged antimicrobials.', 'Infective Endocarditis - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects AIE profile in high-acuity endocarditis care?', 'Which statement best reflects AIE profile in high-acuity endocarditis care?', '[{"id": "a", "text": "Acute infective endocarditis is commonly due to S. aureus, has sudden severe onset, often attacks healthy valves, and is rapidly destructive."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "d", "text": "This pattern is more consistent with Osler nodes."}]'::jsonb, '["a"]'::jsonb, 'Correct because Acute infective endocarditis is commonly due to S. aureus, has sudden severe onset, often attacks healthy valves, and is rapidly destructive. Escalate quickly in high-fever septic presentations with new murmur.', 'Infective Endocarditis - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports SIE profile in this patient with suspected valve infection?', 'Which finding most strongly supports SIE profile in this patient with suspected valve infection?', '[{"id": "a", "text": "Investigate prolonged low-grade constitutional symptoms in at-risk valve patients."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "SIE usually occurs on completely normal valves in this note."}, {"id": "d", "text": "This pattern is more consistent with Roth and splinter findings."}]'::jsonb, '["a"]'::jsonb, 'Correct because Subacute infective endocarditis is commonly due to S. viridans, progresses gradually over weeks to months, and usually occurs on pre-existing valve disease. Investigate prolonged low-grade constitutional symptoms in at-risk valve patients.', 'Infective Endocarditis - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches PATHOGENS mnemonic?', 'The nurse reviews chart data; which interpretation best matches PATHOGENS mnemonic?', '[{"id": "a", "text": "PATHOGENS excludes invasive procedures in this note."}, {"id": "b", "text": "Risk factors are summarized by PATHOGENS: prosthetic valve, acquired valvular disease, trauma/invasive procedures, hypertrophic cardiomyopathy, other structural defects, gram-positive risk, elderly, needles, and sepsis/bacteremia."}, {"id": "c", "text": "Age has no impact on risk in this note."}, {"id": "d", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Risk factors are summarized by PATHOGENS: prosthetic valve, acquired valvular disease, trauma/invasive procedures, hypertrophic cardiomyopathy, other structural defects, gram-positive risk, elderly, needles, and sepsis/bacteremia. Use mnemonic risk screening to trigger earlier blood culture and echo workup.', 'Infective Endocarditis - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Classic findings?', 'Which clinical judgment is most accurate regarding Classic findings?', '[{"id": "a", "text": "Treat new murmur plus fever as high-risk until proven otherwise."}, {"id": "b", "text": "Fever is uncommon in endocarditis in this note."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}]'::jsonb, '["a"]'::jsonb, 'Correct because Fever is the most common sign, with new regurgitant murmur, chills, malaise, night sweats, splenomegaly, and positive blood cultures. Treat new murmur plus fever as high-risk until proven otherwise.', 'Infective Endocarditis - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Janeway lesions?', 'In rapid prioritization, which conclusion aligns best with Janeway lesions?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "Janeway lesions are painful fingertip nodules in this note."}, {"id": "c", "text": "Janeway lesions are painless flat red spots on palms and soles from embolic phenomena."}, {"id": "d", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Janeway lesions are painless flat red spots on palms and soles from embolic phenomena. Differentiate painless Janeway lesions from painful Osler nodes at bedside.', 'Infective Endocarditis - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Osler nodes in high-acuity endocarditis care?', 'Which statement best reflects Osler nodes in high-acuity endocarditis care?', '[{"id": "a", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "b", "text": "This pattern is more consistent with Definite diagnosis combinations."}, {"id": "c", "text": "Osler nodes are a vascular catheter complication in this note."}, {"id": "d", "text": "Use painful digital lesions to strengthen diagnostic probability with other criteria."}]'::jsonb, '["d"]'::jsonb, 'Correct because Osler nodes are painful nodules on fingertips/toes and represent immunologic phenomena. Use painful digital lesions to strengthen diagnostic probability with other criteria.', 'Infective Endocarditis - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Roth and splinter findings in this patient with suspected valve infection?', 'Which finding most strongly supports Roth and splinter findings in this patient with suspected valve infection?', '[{"id": "a", "text": "Splinter hemorrhages are diffuse trunk petechiae in this note."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Roth spots are retinal hemorrhages with pale center, and splinter hemorrhages are linear nail-bed hemorrhages."}, {"id": "d", "text": "Roth spots are painful toe nodules in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Roth spots are retinal hemorrhages with pale center, and splinter hemorrhages are linear nail-bed hemorrhages. Perform focused eye and nail assessment when embolic signs are suspected.', 'Infective Endocarditis - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Embolic complications?', 'The nurse reviews chart data; which interpretation best matches Embolic complications?', '[{"id": "a", "text": "Right-sided emboli primarily cause cerebral emboli in this note."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Endocarditis emboli only affect skin in this note."}, {"id": "d", "text": "Monitor neurologic, renal, and respiratory status for embolic deterioration."}]'::jsonb, '["d"]'::jsonb, 'Correct because Vegetation embolization can cause stroke, renal infarct, and pulmonary emboli in right-sided disease. Monitor neurologic, renal, and respiratory status for embolic deterioration.', 'Infective Endocarditis - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Duke major criteria?', 'Which clinical judgment is most accurate regarding Duke major criteria?', '[{"id": "a", "text": "Major criteria include two positive blood cultures from separate sites and evidence of endocardial involvement (echo/new regurgitation)."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Negative blood cultures satisfy major criteria in this note."}, {"id": "d", "text": "A single nonspecific fever is a major criterion in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Major criteria include two positive blood cultures from separate sites and evidence of endocardial involvement (echo/new regurgitation). Anchor diagnosis on objective microbiology plus valve involvement evidence.', 'Infective Endocarditis - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Duke minor criteria?', 'In rapid prioritization, which conclusion aligns best with Duke minor criteria?', '[{"id": "a", "text": "Any two minor criteria are definite diagnosis in this note."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Count minor criteria carefully when major evidence is incomplete."}, {"id": "d", "text": "This pattern is more consistent with Antibiotic duration."}]'::jsonb, '["c"]'::jsonb, 'Correct because Minor criteria include predisposition, fever >38°C, vascular phenomena, immunologic phenomena, and microbiologic evidence not meeting major. Count minor criteria carefully when major evidence is incomplete.', 'Infective Endocarditis - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Definite diagnosis combinations in high-acuity endocarditis care?', 'Which statement best reflects Definite diagnosis combinations in high-acuity endocarditis care?', '[{"id": "a", "text": "Three minor criteria alone are definitive in this note."}, {"id": "b", "text": "This pattern is more consistent with Organism-specific regimens."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Definite diagnosis is 2 major OR 1 major + 3 minor OR 5 minor criteria."}]'::jsonb, '["d"]'::jsonb, 'Correct because Definite diagnosis is 2 major OR 1 major + 3 minor OR 5 minor criteria. Apply combination thresholds precisely to avoid under/over diagnosis.', 'Infective Endocarditis - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Blood culture protocol in this patient with suspected valve infection?', 'Which finding most strongly supports Blood culture protocol in this patient with suspected valve infection?', '[{"id": "a", "text": "This pattern is more consistent with Surgical indications."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "Antibiotics should start before any cultures in this note."}, {"id": "d", "text": "Preserve microbiologic yield by drawing cultures prior to first dose."}]'::jsonb, '["d"]'::jsonb, 'Correct because Obtain blood cultures ×3 from different sites before starting antibiotics. Preserve microbiologic yield by drawing cultures prior to first dose.', 'Infective Endocarditis - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Echo sensitivity?', 'The nurse reviews chart data; which interpretation best matches Echo sensitivity?', '[{"id": "a", "text": "TTE is always more sensitive than TEE in this note."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "TEE is more sensitive than TTE for detecting vegetations."}, {"id": "d", "text": "Echo has no role in diagnosis in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because TEE is more sensitive than TTE for detecting vegetations. Escalate to TEE when suspicion remains high despite less-sensitive imaging.', 'Infective Endocarditis - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Lab trends?', 'Which clinical judgment is most accurate regarding Lab trends?', '[{"id": "a", "text": "Use labs as supportive evidence while pursuing definitive criteria."}, {"id": "b", "text": "Hematuria excludes endocarditis in this note."}, {"id": "c", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["a"]'::jsonb, 'Correct because CBC can show leukocytosis, ESR/CRP can be elevated, and urinalysis can show hematuria from renal emboli. Use labs as supportive evidence while pursuing definitive criteria.', 'Infective Endocarditis - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Antibiotic duration?', 'In rapid prioritization, which conclusion aligns best with Antibiotic duration?', '[{"id": "a", "text": "This pattern is more consistent with NCLEX synthesis."}, {"id": "b", "text": "Treatment requires IV antibiotics for 4–6 weeks with organism-specific regimens and culture-confirmed clearance."}, {"id": "c", "text": "A 3-day oral course is adequate in this note."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["b"]'::jsonb, 'Correct because Treatment requires IV antibiotics for 4–6 weeks with organism-specific regimens and culture-confirmed clearance. Ensure prolonged IV adherence and follow-up culture monitoring.', 'Infective Endocarditis - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Organism-specific regimens in high-acuity endocarditis care?', 'Which statement best reflects Organism-specific regimens in high-acuity endocarditis care?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "This pattern is more consistent with Definition."}, {"id": "c", "text": "Match regimen to probable/confirmed organism and resistance pattern."}, {"id": "d", "text": "Enterococcus is treated with no antibiotics in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Examples listed: strep with penicillin/ampicillin, staph with nafcillin or vancomycin for MRSA, enterococcus with ampicillin plus gentamicin. Match regimen to probable/confirmed organism and resistance pattern.', 'Infective Endocarditis - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Surgical indications in this patient with suspected valve infection?', 'Which finding most strongly supports Surgical indications in this patient with suspected valve infection?', '[{"id": "a", "text": "Surgery is indicated for severe regurgitation from valve destruction, uncontrolled infection, vegetation >10 mm with embolic risk, prosthetic valve infection, or fungal endocarditis."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Fungal endocarditis is never surgical in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Surgery is indicated for severe regurgitation from valve destruction, uncontrolled infection, vegetation >10 mm with embolic risk, prosthetic valve infection, or fungal endocarditis. Escalate to surgical consultation when medical therapy is insufficient or embolic risk is high.', 'Infective Endocarditis - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Nursing priorities?', 'The nurse reviews chart data; which interpretation best matches Nursing priorities?', '[{"id": "a", "text": "Prioritize early detection of progression while maintaining reliable IV therapy."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Short peripheral IV rotation is preferred over stable long-term access in this note."}, {"id": "d", "text": "This pattern is more consistent with Organisms overview."}]'::jsonb, '["a"]'::jsonb, 'Correct because Nursing priorities include cultures before antibiotics, fever monitoring, new murmur assessment, embolic surveillance, and long-term IV access care. Prioritize early detection of progression while maintaining reliable IV therapy.', 'Infective Endocarditis - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Prophylaxis?', 'Which clinical judgment is most accurate regarding Prophylaxis?', '[{"id": "a", "text": "This pattern is more consistent with Non-infective forms."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "High-risk patients should receive amoxicillin prophylaxis before dental procedures."}, {"id": "d", "text": "Prophylaxis is only after procedures in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because High-risk patients should receive amoxicillin prophylaxis before dental procedures. Prevent procedure-related bacteremia in vulnerable cardiac patients.', 'Infective Endocarditis - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with NCLEX synthesis?', 'In rapid prioritization, which conclusion aligns best with NCLEX synthesis?', '[{"id": "a", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "b", "text": "Treat clustered red flags as a high-acuity syndrome requiring rapid action."}, {"id": "c", "text": "Culture positivity should delay treatment in this note."}, {"id": "d", "text": "Embolic signs lower IE suspicion in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because High-yield pattern: fever + new regurgitant murmur + positive cultures + embolic signs should trigger urgent IE workup and treatment. Treat clustered red flags as a high-acuity syndrome requiring rapid action.', 'Infective Endocarditis - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Definition in high-acuity endocarditis care?', 'Which statement best reflects Definition in high-acuity endocarditis care?', '[{"id": "a", "text": "Vegetations in this note are sterile in infective cases."}, {"id": "b", "text": "This pattern is more consistent with SIE profile."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms."}]'::jsonb, '["d"]'::jsonb, 'Correct because Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms. Treat suspected valve infection urgently to limit embolic and valvular destruction.', 'Infective Endocarditis - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Valve distribution in this patient with suspected valve infection?', 'Which finding most strongly supports Valve distribution in this patient with suspected valve infection?', '[{"id": "a", "text": "This pattern is more consistent with PATHOGENS mnemonic."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Use risk profile to anticipate likely side/valve complications."}, {"id": "d", "text": "Valve choice is random and unrelated to risk factors in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Mitral valve is commonly affected on the left side, and tricuspid involvement is common in IV drug use (right-sided). Use risk profile to anticipate likely side/valve complications.', 'Infective Endocarditis - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Organisms overview?', 'The nurse reviews chart data; which interpretation best matches Organisms overview?', '[{"id": "a", "text": "Common organisms include Streptococcus viridans, Staphylococcus aureus, Enterococcus, S. epidermidis on prosthetic valves, and HACEK organisms."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "d", "text": "HACEK organisms are excluded in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Common organisms include Streptococcus viridans, Staphylococcus aureus, Enterococcus, S. epidermidis on prosthetic valves, and HACEK organisms. Start broad directed therapy and narrow with culture data.', 'Infective Endocarditis - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Non-infective forms?', 'Which clinical judgment is most accurate regarding Non-infective forms?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "This pattern is more consistent with Janeway lesions."}, {"id": "c", "text": "Libman-Sacks is caused by S. aureus in this note."}, {"id": "d", "text": "Differentiate sterile vegetations from true infection before prolonged antimicrobials."}]'::jsonb, '["d"]'::jsonb, 'Correct because Non-infective endocarditis includes marantic (cancer/wasting) and Libman-Sacks (SLE), where vegetations have no organisms. Differentiate sterile vegetations from true infection before prolonged antimicrobials.', 'Infective Endocarditis - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with AIE profile?', 'In rapid prioritization, which conclusion aligns best with AIE profile?', '[{"id": "a", "text": "Acute infective endocarditis is commonly due to S. aureus, has sudden severe onset, often attacks healthy valves, and is rapidly destructive."}, {"id": "b", "text": "This pattern is more consistent with Osler nodes."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "AIE is less destructive than subacute disease in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Acute infective endocarditis is commonly due to S. aureus, has sudden severe onset, often attacks healthy valves, and is rapidly destructive. Escalate quickly in high-fever septic presentations with new murmur.', 'Infective Endocarditis - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects SIE profile in high-acuity endocarditis care?', 'Which statement best reflects SIE profile in high-acuity endocarditis care?', '[{"id": "a", "text": "SIE usually occurs on completely normal valves in this note."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "SIE typically presents as sudden sepsis in this note."}, {"id": "d", "text": "Investigate prolonged low-grade constitutional symptoms in at-risk valve patients."}]'::jsonb, '["d"]'::jsonb, 'Correct because Subacute infective endocarditis is commonly due to S. viridans, progresses gradually over weeks to months, and usually occurs on pre-existing valve disease. Investigate prolonged low-grade constitutional symptoms in at-risk valve patients.', 'Infective Endocarditis - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports PATHOGENS mnemonic in this patient with suspected valve infection?', 'Which finding most strongly supports PATHOGENS mnemonic in this patient with suspected valve infection?', '[{"id": "a", "text": "This pattern is more consistent with Embolic complications."}, {"id": "b", "text": "Risk factors are summarized by PATHOGENS: prosthetic valve, acquired valvular disease, trauma/invasive procedures, hypertrophic cardiomyopathy, other structural defects, gram-positive risk, elderly, needles, and sepsis/bacteremia."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "PATHOGENS excludes invasive procedures in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Risk factors are summarized by PATHOGENS: prosthetic valve, acquired valvular disease, trauma/invasive procedures, hypertrophic cardiomyopathy, other structural defects, gram-positive risk, elderly, needles, and sepsis/bacteremia. Use mnemonic risk screening to trigger earlier blood culture and echo workup.', 'Infective Endocarditis - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Classic findings?', 'The nurse reviews chart data; which interpretation best matches Classic findings?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "Fever is uncommon in endocarditis in this note."}, {"id": "c", "text": "This pattern is more consistent with Duke major criteria."}, {"id": "d", "text": "Treat new murmur plus fever as high-risk until proven otherwise."}]'::jsonb, '["d"]'::jsonb, 'Correct because Fever is the most common sign, with new regurgitant murmur, chills, malaise, night sweats, splenomegaly, and positive blood cultures. Treat new murmur plus fever as high-risk until proven otherwise.', 'Infective Endocarditis - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Janeway lesions?', 'Which clinical judgment is most accurate regarding Janeway lesions?', '[{"id": "a", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "b", "text": "Janeway lesions are painless flat red spots on palms and soles from embolic phenomena."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Janeway lesions are painful fingertip nodules in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Janeway lesions are painless flat red spots on palms and soles from embolic phenomena. Differentiate painless Janeway lesions from painful Osler nodes at bedside.', 'Infective Endocarditis - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Osler nodes?', 'In rapid prioritization, which conclusion aligns best with Osler nodes?', '[{"id": "a", "text": "Osler nodes are painless palm lesions in this note."}, {"id": "b", "text": "Osler nodes are a vascular catheter complication in this note."}, {"id": "c", "text": "Use painful digital lesions to strengthen diagnostic probability with other criteria."}, {"id": "d", "text": "This pattern is more consistent with Definite diagnosis combinations."}]'::jsonb, '["c"]'::jsonb, 'Correct because Osler nodes are painful nodules on fingertips/toes and represent immunologic phenomena. Use painful digital lesions to strengthen diagnostic probability with other criteria.', 'Infective Endocarditis - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Roth and splinter findings in high-acuity endocarditis care?', 'Which statement best reflects Roth and splinter findings in high-acuity endocarditis care?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Roth spots are retinal hemorrhages with pale center, and splinter hemorrhages are linear nail-bed hemorrhages."}, {"id": "d", "text": "Roth spots are painful toe nodules in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Roth spots are retinal hemorrhages with pale center, and splinter hemorrhages are linear nail-bed hemorrhages. Perform focused eye and nail assessment when embolic signs are suspected.', 'Infective Endocarditis - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Embolic complications in this patient with suspected valve infection?', 'Which finding most strongly supports Embolic complications in this patient with suspected valve infection?', '[{"id": "a", "text": "This pattern is more consistent with Echo sensitivity."}, {"id": "b", "text": "Endocarditis emboli only affect skin in this note."}, {"id": "c", "text": "Monitor neurologic, renal, and respiratory status for embolic deterioration."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["c"]'::jsonb, 'Correct because Vegetation embolization can cause stroke, renal infarct, and pulmonary emboli in right-sided disease. Monitor neurologic, renal, and respiratory status for embolic deterioration.', 'Infective Endocarditis - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Duke major criteria?', 'The nurse reviews chart data; which interpretation best matches Duke major criteria?', '[{"id": "a", "text": "Negative blood cultures satisfy major criteria in this note."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Major criteria include two positive blood cultures from separate sites and evidence of endocardial involvement (echo/new regurgitation)."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["c"]'::jsonb, 'Correct because Major criteria include two positive blood cultures from separate sites and evidence of endocardial involvement (echo/new regurgitation). Anchor diagnosis on objective microbiology plus valve involvement evidence.', 'Infective Endocarditis - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Duke minor criteria?', 'Which clinical judgment is most accurate regarding Duke minor criteria?', '[{"id": "a", "text": "Count minor criteria carefully when major evidence is incomplete."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Predisposing condition is excluded from minor criteria in this note."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["a"]'::jsonb, 'Correct because Minor criteria include predisposition, fever >38°C, vascular phenomena, immunologic phenomena, and microbiologic evidence not meeting major. Count minor criteria carefully when major evidence is incomplete.', 'Infective Endocarditis - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Definite diagnosis combinations?', 'In rapid prioritization, which conclusion aligns best with Definite diagnosis combinations?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "Three minor criteria alone are definitive in this note."}, {"id": "c", "text": "This pattern is more consistent with Organism-specific regimens."}, {"id": "d", "text": "Definite diagnosis is 2 major OR 1 major + 3 minor OR 5 minor criteria."}]'::jsonb, '["d"]'::jsonb, 'Correct because Definite diagnosis is 2 major OR 1 major + 3 minor OR 5 minor criteria. Apply combination thresholds precisely to avoid under/over diagnosis.', 'Infective Endocarditis - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Blood culture protocol in high-acuity endocarditis care?', 'Which statement best reflects Blood culture protocol in high-acuity endocarditis care?', '[{"id": "a", "text": "Preserve microbiologic yield by drawing cultures prior to first dose."}, {"id": "b", "text": "Antibiotics should start before any cultures in this note."}, {"id": "c", "text": "Only one blood culture is needed in this note."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["a"]'::jsonb, 'Correct because Obtain blood cultures ×3 from different sites before starting antibiotics. Preserve microbiologic yield by drawing cultures prior to first dose.', 'Infective Endocarditis - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Echo sensitivity in this patient with suspected valve infection?', 'Which finding most strongly supports Echo sensitivity in this patient with suspected valve infection?', '[{"id": "a", "text": "TEE is more sensitive than TTE for detecting vegetations."}, {"id": "b", "text": "TTE is always more sensitive than TEE in this note."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "This pattern is more consistent with Nursing priorities."}]'::jsonb, '["a"]'::jsonb, 'Correct because TEE is more sensitive than TTE for detecting vegetations. Escalate to TEE when suspicion remains high despite less-sensitive imaging.', 'Infective Endocarditis - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Lab trends?', 'The nurse reviews chart data; which interpretation best matches Lab trends?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "Inflammatory markers are always normal in this note."}, {"id": "c", "text": "This pattern is more consistent with Prophylaxis."}, {"id": "d", "text": "Use labs as supportive evidence while pursuing definitive criteria."}]'::jsonb, '["d"]'::jsonb, 'Correct because CBC can show leukocytosis, ESR/CRP can be elevated, and urinalysis can show hematuria from renal emboli. Use labs as supportive evidence while pursuing definitive criteria.', 'Infective Endocarditis - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Antibiotic duration?', 'Which clinical judgment is most accurate regarding Antibiotic duration?', '[{"id": "a", "text": "No culture follow-up is needed after therapy starts in this note."}, {"id": "b", "text": "A 3-day oral course is adequate in this note."}, {"id": "c", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "d", "text": "Treatment requires IV antibiotics for 4–6 weeks with organism-specific regimens and culture-confirmed clearance."}]'::jsonb, '["d"]'::jsonb, 'Correct because Treatment requires IV antibiotics for 4–6 weeks with organism-specific regimens and culture-confirmed clearance. Ensure prolonged IV adherence and follow-up culture monitoring.', 'Infective Endocarditis - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Organism-specific regimens?', 'In rapid prioritization, which conclusion aligns best with Organism-specific regimens?', '[{"id": "a", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Enterococcus is treated with no antibiotics in this note."}, {"id": "d", "text": "Match regimen to probable/confirmed organism and resistance pattern."}]'::jsonb, '["d"]'::jsonb, 'Correct because Examples listed: strep with penicillin/ampicillin, staph with nafcillin or vancomycin for MRSA, enterococcus with ampicillin plus gentamicin. Match regimen to probable/confirmed organism and resistance pattern.', 'Infective Endocarditis - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Surgical indications in high-acuity endocarditis care?', 'Which statement best reflects Surgical indications in high-acuity endocarditis care?', '[{"id": "a", "text": "All cases should avoid surgery regardless of deterioration in this note."}, {"id": "b", "text": "Surgery is indicated for severe regurgitation from valve destruction, uncontrolled infection, vegetation >10 mm with embolic risk, prosthetic valve infection, or fungal endocarditis."}, {"id": "c", "text": "This pattern is more consistent with Valve distribution."}, {"id": "d", "text": "Fungal endocarditis is never surgical in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Surgery is indicated for severe regurgitation from valve destruction, uncontrolled infection, vegetation >10 mm with embolic risk, prosthetic valve infection, or fungal endocarditis. Escalate to surgical consultation when medical therapy is insufficient or embolic risk is high.', 'Infective Endocarditis - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Nursing priorities in this patient with suspected valve infection?', 'Which finding most strongly supports Nursing priorities in this patient with suspected valve infection?', '[{"id": "a", "text": "Murmur reassessment is unnecessary in this note."}, {"id": "b", "text": "Prioritize early detection of progression while maintaining reliable IV therapy."}, {"id": "c", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "d", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Nursing priorities include cultures before antibiotics, fever monitoring, new murmur assessment, embolic surveillance, and long-term IV access care. Prioritize early detection of progression while maintaining reliable IV therapy.', 'Infective Endocarditis - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews chart data; which interpretation best matches Prophylaxis?', 'The nurse reviews chart data; which interpretation best matches Prophylaxis?', '[{"id": "a", "text": "High-risk patients should receive amoxicillin prophylaxis before dental procedures."}, {"id": "b", "text": "Dental prophylaxis is unnecessary in high-risk patients in this note."}, {"id": "c", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "d", "text": "This pattern is more consistent with Non-infective forms."}]'::jsonb, '["a"]'::jsonb, 'Correct because High-risk patients should receive amoxicillin prophylaxis before dental procedures. Prevent procedure-related bacteremia in vulnerable cardiac patients.', 'Infective Endocarditis - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding NCLEX synthesis?', 'Which clinical judgment is most accurate regarding NCLEX synthesis?', '[{"id": "a", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "b", "text": "Cultures should be deferred until after several antibiotic doses."}, {"id": "c", "text": "Treat clustered red flags as a high-acuity syndrome requiring rapid action."}, {"id": "d", "text": "Embolic signs lower IE suspicion in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because High-yield pattern: fever + new regurgitant murmur + positive cultures + embolic signs should trigger urgent IE workup and treatment. Treat clustered red flags as a high-acuity syndrome requiring rapid action.', 'Infective Endocarditis - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which conclusion aligns best with Definition?', 'In rapid prioritization, which conclusion aligns best with Definition?', '[{"id": "a", "text": "Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "This pattern is more consistent with SIE profile."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["a"]'::jsonb, 'Correct because Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms. Treat suspected valve infection urgently to limit embolic and valvular destruction.', 'Infective Endocarditis - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Valve distribution in high-acuity endocarditis care?', 'Which statement best reflects Valve distribution in high-acuity endocarditis care?', '[{"id": "a", "text": "Use risk profile to anticipate likely side/valve complications."}, {"id": "b", "text": "Because embolic risk is minimal, urgent workup is unnecessary."}, {"id": "c", "text": "Valve choice is random and unrelated to risk factors in this note."}, {"id": "d", "text": "Cultures should be deferred until after several antibiotic doses."}]'::jsonb, '["a"]'::jsonb, 'Correct because Mitral valve is commonly affected on the left side, and tricuspid involvement is common in IV drug use (right-sided). Use risk profile to anticipate likely side/valve complications.', 'Infective Endocarditis - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Valve involvement is a central feature."}, {"id": "b", "text": "Endocarditis is infection of the pericardium in this note."}, {"id": "c", "text": "Vegetations include fibrin, platelets, and microorganisms."}, {"id": "d", "text": "Endocarditis affects the inner lining and valves."}, {"id": "e", "text": "Vegetations in this note are sterile in infective cases."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms.', 'Infective Endocarditis - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Valve distribution, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Valve distribution, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "IV drug use is linked to right-sided (tricuspid) disease."}, {"id": "b", "text": "Mitral valve involvement is common in this note."}, {"id": "c", "text": "Valve choice is random and unrelated to risk factors in this note."}, {"id": "d", "text": "IV drug use is primarily linked to left-sided mitral lesions in this note."}, {"id": "e", "text": "Valve pattern can reflect exposure risks."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Mitral valve is commonly affected on the left side, and tricuspid involvement is common in IV drug use (right-sided).', 'Infective Endocarditis - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Organisms overview. Which items should be included? (Select all that apply)', 'The nurse plans care around Organisms overview. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Enterococcus is associated with GI/GU sources."}, {"id": "b", "text": "S. viridans and S. aureus are major pathogens listed."}, {"id": "c", "text": "HACEK organisms are excluded in this note."}, {"id": "d", "text": "Prosthetic valves are linked with S. epidermidis in this note."}, {"id": "e", "text": "Only viral organisms cause infective endocarditis in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Common organisms include Streptococcus viridans, Staphylococcus aureus, Enterococcus, S. epidermidis on prosthetic valves, and HACEK organisms.', 'Infective Endocarditis - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Non-infective forms rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Non-infective forms rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Libman-Sacks is associated with SLE."}, {"id": "b", "text": "All endocarditis forms in this note are infectious."}, {"id": "c", "text": "Libman-Sacks is caused by S. aureus in this note."}, {"id": "d", "text": "Non-infective vegetations lack organisms."}, {"id": "e", "text": "Marantic endocarditis is a sterile form in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Non-infective endocarditis includes marantic (cancer/wasting) and Libman-Sacks (SLE), where vegetations have no organisms.', 'Infective Endocarditis - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with AIE profile? (Select all that apply)', 'During reassessment, which observations align with AIE profile? (Select all that apply)', '[{"id": "a", "text": "AIE onset is sudden and severe in this note."}, {"id": "b", "text": "AIE is less destructive than subacute disease in this note."}, {"id": "c", "text": "S. aureus is the common acute organism listed."}, {"id": "d", "text": "AIE is insidious over months in this note."}, {"id": "e", "text": "AIE can involve previously healthy valves."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Acute infective endocarditis is commonly due to S. aureus, has sudden severe onset, often attacks healthy valves, and is rapidly destructive.', 'Infective Endocarditis - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for SIE profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for SIE profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "SIE usually occurs on completely normal valves in this note."}, {"id": "b", "text": "S. viridans is the common subacute organism listed."}, {"id": "c", "text": "Pre-existing valve disease is commonly present in SIE."}, {"id": "d", "text": "SIE course is gradual in this note."}, {"id": "e", "text": "SIE typically presents as sudden sepsis in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Subacute infective endocarditis is commonly due to S. viridans, progresses gradually over weeks to months, and usually occurs on pre-existing valve disease.', 'Infective Endocarditis - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and PATHOGENS mnemonic, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and PATHOGENS mnemonic, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Sepsis/bacteremia source is included in PATHOGENS."}, {"id": "b", "text": "PATHOGENS excludes invasive procedures in this note."}, {"id": "c", "text": "Prosthetic valves are included in PATHOGENS."}, {"id": "d", "text": "Age has no impact on risk in this note."}, {"id": "e", "text": "Needles/IV drug use is included in PATHOGENS."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Risk factors are summarized by PATHOGENS: prosthetic valve, acquired valvular disease, trauma/invasive procedures, hypertrophic cardiomyopathy, other structural defects, gram-positive risk, elderly, needles, and sepsis/bacteremia.', 'Infective Endocarditis - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Classic findings. Which items should be included? (Select all that apply)', 'The nurse plans care around Classic findings. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Fever is emphasized as the most common sign."}, {"id": "b", "text": "New regurgitant murmur is a major clue."}, {"id": "c", "text": "A new murmur argues against endocarditis in this note."}, {"id": "d", "text": "Positive blood cultures support diagnosis."}, {"id": "e", "text": "Fever is uncommon in endocarditis in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Fever is the most common sign, with new regurgitant murmur, chills, malaise, night sweats, splenomegaly, and positive blood cultures.', 'Infective Endocarditis - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Janeway lesions rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Janeway lesions rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Janeway lesions are painless in this note."}, {"id": "b", "text": "They are found on palms/soles."}, {"id": "c", "text": "Janeway lesions are retinal findings in this note."}, {"id": "d", "text": "Janeway lesions are painful fingertip nodules in this note."}, {"id": "e", "text": "They reflect embolic phenomena."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Janeway lesions are painless flat red spots on palms and soles from embolic phenomena.', 'Infective Endocarditis - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Osler nodes? (Select all that apply)', 'During reassessment, which observations align with Osler nodes? (Select all that apply)', '[{"id": "a", "text": "Osler nodes are painful in this note."}, {"id": "b", "text": "Osler nodes are painless palm lesions in this note."}, {"id": "c", "text": "Osler nodes are a vascular catheter complication in this note."}, {"id": "d", "text": "They are categorized as immunologic phenomena in criteria."}, {"id": "e", "text": "They occur on fingers or toes."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Osler nodes are painful nodules on fingertips/toes and represent immunologic phenomena.', 'Infective Endocarditis - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Roth and splinter findings. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Roth and splinter findings. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Splinter hemorrhages are diffuse trunk petechiae in this note."}, {"id": "b", "text": "Roth spots are retinal hemorrhages with pale centers."}, {"id": "c", "text": "Splinter hemorrhages appear in nail beds."}, {"id": "d", "text": "Roth spots are painful toe nodules in this note."}, {"id": "e", "text": "Both support systemic endocarditis manifestations."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Roth spots are retinal hemorrhages with pale center, and splinter hemorrhages are linear nail-bed hemorrhages.', 'Infective Endocarditis - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Embolic complications, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Embolic complications, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Renal infarct is listed as an embolic complication."}, {"id": "b", "text": "Right-sided disease can embolize to lungs (PE)."}, {"id": "c", "text": "Stroke is an embolic complication listed."}, {"id": "d", "text": "Endocarditis emboli only affect skin in this note."}, {"id": "e", "text": "Right-sided emboli primarily cause cerebral emboli in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Vegetation embolization can cause stroke, renal infarct, and pulmonary emboli in right-sided disease.', 'Infective Endocarditis - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Duke major criteria. Which items should be included? (Select all that apply)', 'The nurse plans care around Duke major criteria. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Negative blood cultures satisfy major criteria in this note."}, {"id": "b", "text": "A single nonspecific fever is a major criterion in this note."}, {"id": "c", "text": "New valve regurgitation supports major criteria."}, {"id": "d", "text": "Echo evidence of endocardial involvement is major."}, {"id": "e", "text": "Two separate positive blood cultures are a major criterion."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Major criteria include two positive blood cultures from separate sites and evidence of endocardial involvement (echo/new regurgitation).', 'Infective Endocarditis - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Duke minor criteria rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Duke minor criteria rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Immunologic findings like Osler/Roth count as minor."}, {"id": "b", "text": "Any two minor criteria are definite diagnosis in this note."}, {"id": "c", "text": "Vascular phenomena count as minor criteria."}, {"id": "d", "text": "Predisposing condition is excluded from minor criteria in this note."}, {"id": "e", "text": "Fever above 38°C is a minor criterion."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Minor criteria include predisposition, fever >38°C, vascular phenomena, immunologic phenomena, and microbiologic evidence not meeting major.', 'Infective Endocarditis - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Definite diagnosis combinations? (Select all that apply)', 'During reassessment, which observations align with Definite diagnosis combinations? (Select all that apply)', '[{"id": "a", "text": "One major plus three minor can establish diagnosis."}, {"id": "b", "text": "One major alone is always definitive in this note."}, {"id": "c", "text": "Five minor criteria can establish diagnosis."}, {"id": "d", "text": "Three minor criteria alone are definitive in this note."}, {"id": "e", "text": "Two major criteria can establish definite diagnosis."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Definite diagnosis is 2 major OR 1 major + 3 minor OR 5 minor criteria.', 'Infective Endocarditis - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Blood culture protocol. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Blood culture protocol. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Only one blood culture is needed in this note."}, {"id": "b", "text": "Antibiotics should start before any cultures in this note."}, {"id": "c", "text": "Cultures should be drawn before antibiotics."}, {"id": "d", "text": "Three culture sets are recommended in this note."}, {"id": "e", "text": "Different collection sites are required."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Obtain blood cultures ×3 from different sites before starting antibiotics.', 'Infective Endocarditis - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Echo sensitivity, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Echo sensitivity, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "TEE is more sensitive than TTE in this note."}, {"id": "b", "text": "Vegetation detection is central to diagnosis."}, {"id": "c", "text": "TTE is always more sensitive than TEE in this note."}, {"id": "d", "text": "Echo has no role in diagnosis in this note."}, {"id": "e", "text": "Echo evaluates endocardial involvement."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: TEE is more sensitive than TTE for detecting vegetations.', 'Infective Endocarditis - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Lab trends. Which items should be included? (Select all that apply)', 'The nurse plans care around Lab trends. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Hematuria excludes endocarditis in this note."}, {"id": "b", "text": "Inflammatory markers are always normal in this note."}, {"id": "c", "text": "Hematuria may suggest renal embolic involvement."}, {"id": "d", "text": "Leukocytosis is listed in workup."}, {"id": "e", "text": "ESR/CRP elevation is listed in workup."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: CBC can show leukocytosis, ESR/CRP can be elevated, and urinalysis can show hematuria from renal emboli.', 'Infective Endocarditis - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Antibiotic duration rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Antibiotic duration rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Regimen depends on organism type."}, {"id": "b", "text": "IV treatment is typically 4–6 weeks."}, {"id": "c", "text": "No culture follow-up is needed after therapy starts in this note."}, {"id": "d", "text": "Culture clearance monitoring is required."}, {"id": "e", "text": "A 3-day oral course is adequate in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Treatment requires IV antibiotics for 4–6 weeks with organism-specific regimens and culture-confirmed clearance.', 'Infective Endocarditis - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Organism-specific regimens? (Select all that apply)', 'During reassessment, which observations align with Organism-specific regimens? (Select all that apply)', '[{"id": "a", "text": "Enterococcus regimen includes ampicillin + gentamicin."}, {"id": "b", "text": "Enterococcus is treated with no antibiotics in this note."}, {"id": "c", "text": "MRSA is first-line treated with amoxicillin alone in this note."}, {"id": "d", "text": "Strep regimens include penicillin or ampicillin."}, {"id": "e", "text": "MRSA coverage can require vancomycin."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Examples listed: strep with penicillin/ampicillin, staph with nafcillin or vancomycin for MRSA, enterococcus with ampicillin plus gentamicin.', 'Infective Endocarditis - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Surgical indications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Surgical indications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Uncontrolled infection despite antibiotics is an indication."}, {"id": "b", "text": "Fungal endocarditis is never surgical in this note."}, {"id": "c", "text": "Severe regurgitation from valve destruction is an indication."}, {"id": "d", "text": "Vegetation >10 mm with embolic risk is an indication."}, {"id": "e", "text": "All cases should avoid surgery regardless of deterioration in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Surgery is indicated for severe regurgitation from valve destruction, uncontrolled infection, vegetation >10 mm with embolic risk, prosthetic valve infection, or fungal endocarditis.', 'Infective Endocarditis - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Nursing priorities, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Nursing priorities, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "New murmur assessment is emphasized."}, {"id": "b", "text": "Fever monitoring is emphasized."}, {"id": "c", "text": "Murmur reassessment is unnecessary in this note."}, {"id": "d", "text": "Long-term IV access maintenance is emphasized."}, {"id": "e", "text": "Short peripheral IV rotation is preferred over stable long-term access in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Nursing priorities include cultures before antibiotics, fever monitoring, new murmur assessment, embolic surveillance, and long-term IV access care.', 'Infective Endocarditis - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Prophylaxis. Which items should be included? (Select all that apply)', 'The nurse plans care around Prophylaxis. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Prevention targets bacteremia-triggered endocarditis."}, {"id": "b", "text": "Amoxicillin is the prophylactic example provided."}, {"id": "c", "text": "Prophylaxis is only after procedures in this note."}, {"id": "d", "text": "Dental prophylaxis is unnecessary in high-risk patients in this note."}, {"id": "e", "text": "Dental prophylaxis is listed for high-risk groups."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: High-risk patients should receive amoxicillin prophylaxis before dental procedures.', 'Infective Endocarditis - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support NCLEX synthesis rather than an alternative diagnosis? (Select all that apply)', 'Which findings support NCLEX synthesis rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Embolic signs lower IE suspicion in this note."}, {"id": "b", "text": "Culture positivity should delay treatment in this note."}, {"id": "c", "text": "Embolic signs increase concern for active IE."}, {"id": "d", "text": "Fever plus new murmur is a key cluster."}, {"id": "e", "text": "Positive cultures strengthen urgency."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: High-yield pattern: fever + new regurgitant murmur + positive cultures + embolic signs should trigger urgent IE workup and treatment.', 'Infective Endocarditis - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Definition? (Select all that apply)', 'During reassessment, which observations align with Definition? (Select all that apply)', '[{"id": "a", "text": "Valve involvement is a central feature."}, {"id": "b", "text": "Endocarditis is infection of the pericardium in this note."}, {"id": "c", "text": "Endocarditis affects the inner lining and valves."}, {"id": "d", "text": "Vegetations in this note are sterile in infective cases."}, {"id": "e", "text": "Vegetations include fibrin, platelets, and microorganisms."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms.', 'Infective Endocarditis - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Valve distribution. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Valve distribution. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Valve pattern can reflect exposure risks."}, {"id": "b", "text": "Valve choice is random and unrelated to risk factors in this note."}, {"id": "c", "text": "Mitral valve involvement is common in this note."}, {"id": "d", "text": "IV drug use is primarily linked to left-sided mitral lesions in this note."}, {"id": "e", "text": "IV drug use is linked to right-sided (tricuspid) disease."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Mitral valve is commonly affected on the left side, and tricuspid involvement is common in IV drug use (right-sided).', 'Infective Endocarditis - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Organisms overview, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Organisms overview, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Only viral organisms cause infective endocarditis in this note."}, {"id": "b", "text": "Prosthetic valves are linked with S. epidermidis in this note."}, {"id": "c", "text": "HACEK organisms are excluded in this note."}, {"id": "d", "text": "Enterococcus is associated with GI/GU sources."}, {"id": "e", "text": "S. viridans and S. aureus are major pathogens listed."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Common organisms include Streptococcus viridans, Staphylococcus aureus, Enterococcus, S. epidermidis on prosthetic valves, and HACEK organisms.', 'Infective Endocarditis - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Non-infective forms. Which items should be included? (Select all that apply)', 'The nurse plans care around Non-infective forms. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Libman-Sacks is caused by S. aureus in this note."}, {"id": "b", "text": "Marantic endocarditis is a sterile form in this note."}, {"id": "c", "text": "Non-infective vegetations lack organisms."}, {"id": "d", "text": "All endocarditis forms in this note are infectious."}, {"id": "e", "text": "Libman-Sacks is associated with SLE."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Non-infective endocarditis includes marantic (cancer/wasting) and Libman-Sacks (SLE), where vegetations have no organisms.', 'Infective Endocarditis - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support AIE profile rather than an alternative diagnosis? (Select all that apply)', 'Which findings support AIE profile rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "AIE onset is sudden and severe in this note."}, {"id": "b", "text": "S. aureus is the common acute organism listed."}, {"id": "c", "text": "AIE can involve previously healthy valves."}, {"id": "d", "text": "AIE is insidious over months in this note."}, {"id": "e", "text": "AIE is less destructive than subacute disease in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Acute infective endocarditis is commonly due to S. aureus, has sudden severe onset, often attacks healthy valves, and is rapidly destructive.', 'Infective Endocarditis - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with SIE profile? (Select all that apply)', 'During reassessment, which observations align with SIE profile? (Select all that apply)', '[{"id": "a", "text": "SIE course is gradual in this note."}, {"id": "b", "text": "S. viridans is the common subacute organism listed."}, {"id": "c", "text": "Pre-existing valve disease is commonly present in SIE."}, {"id": "d", "text": "SIE typically presents as sudden sepsis in this note."}, {"id": "e", "text": "SIE usually occurs on completely normal valves in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Subacute infective endocarditis is commonly due to S. viridans, progresses gradually over weeks to months, and usually occurs on pre-existing valve disease.', 'Infective Endocarditis - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for PATHOGENS mnemonic. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for PATHOGENS mnemonic. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Needles/IV drug use is included in PATHOGENS."}, {"id": "b", "text": "Age has no impact on risk in this note."}, {"id": "c", "text": "PATHOGENS excludes invasive procedures in this note."}, {"id": "d", "text": "Sepsis/bacteremia source is included in PATHOGENS."}, {"id": "e", "text": "Prosthetic valves are included in PATHOGENS."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Risk factors are summarized by PATHOGENS: prosthetic valve, acquired valvular disease, trauma/invasive procedures, hypertrophic cardiomyopathy, other structural defects, gram-positive risk, elderly, needles, and sepsis/bacteremia.', 'Infective Endocarditis - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Classic findings, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Classic findings, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "New regurgitant murmur is a major clue."}, {"id": "b", "text": "Fever is uncommon in endocarditis in this note."}, {"id": "c", "text": "Fever is emphasized as the most common sign."}, {"id": "d", "text": "Positive blood cultures support diagnosis."}, {"id": "e", "text": "A new murmur argues against endocarditis in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Fever is the most common sign, with new regurgitant murmur, chills, malaise, night sweats, splenomegaly, and positive blood cultures.', 'Infective Endocarditis - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Janeway lesions. Which items should be included? (Select all that apply)', 'The nurse plans care around Janeway lesions. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Janeway lesions are retinal findings in this note."}, {"id": "b", "text": "They are found on palms/soles."}, {"id": "c", "text": "Janeway lesions are painful fingertip nodules in this note."}, {"id": "d", "text": "Janeway lesions are painless in this note."}, {"id": "e", "text": "They reflect embolic phenomena."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Janeway lesions are painless flat red spots on palms and soles from embolic phenomena.', 'Infective Endocarditis - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Osler nodes rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Osler nodes rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Osler nodes are a vascular catheter complication in this note."}, {"id": "b", "text": "Osler nodes are painful in this note."}, {"id": "c", "text": "They are categorized as immunologic phenomena in criteria."}, {"id": "d", "text": "They occur on fingers or toes."}, {"id": "e", "text": "Osler nodes are painless palm lesions in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Osler nodes are painful nodules on fingertips/toes and represent immunologic phenomena.', 'Infective Endocarditis - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Roth and splinter findings? (Select all that apply)', 'During reassessment, which observations align with Roth and splinter findings? (Select all that apply)', '[{"id": "a", "text": "Splinter hemorrhages are diffuse trunk petechiae in this note."}, {"id": "b", "text": "Roth spots are retinal hemorrhages with pale centers."}, {"id": "c", "text": "Roth spots are painful toe nodules in this note."}, {"id": "d", "text": "Splinter hemorrhages appear in nail beds."}, {"id": "e", "text": "Both support systemic endocarditis manifestations."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Roth spots are retinal hemorrhages with pale center, and splinter hemorrhages are linear nail-bed hemorrhages.', 'Infective Endocarditis - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Embolic complications. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Embolic complications. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Right-sided disease can embolize to lungs (PE)."}, {"id": "b", "text": "Right-sided emboli primarily cause cerebral emboli in this note."}, {"id": "c", "text": "Stroke is an embolic complication listed."}, {"id": "d", "text": "Renal infarct is listed as an embolic complication."}, {"id": "e", "text": "Endocarditis emboli only affect skin in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Vegetation embolization can cause stroke, renal infarct, and pulmonary emboli in right-sided disease.', 'Infective Endocarditis - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Duke major criteria, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Duke major criteria, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Echo evidence of endocardial involvement is major."}, {"id": "b", "text": "New valve regurgitation supports major criteria."}, {"id": "c", "text": "A single nonspecific fever is a major criterion in this note."}, {"id": "d", "text": "Two separate positive blood cultures are a major criterion."}, {"id": "e", "text": "Negative blood cultures satisfy major criteria in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Major criteria include two positive blood cultures from separate sites and evidence of endocardial involvement (echo/new regurgitation).', 'Infective Endocarditis - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Duke minor criteria. Which items should be included? (Select all that apply)', 'The nurse plans care around Duke minor criteria. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Predisposing condition is excluded from minor criteria in this note."}, {"id": "b", "text": "Any two minor criteria are definite diagnosis in this note."}, {"id": "c", "text": "Immunologic findings like Osler/Roth count as minor."}, {"id": "d", "text": "Fever above 38°C is a minor criterion."}, {"id": "e", "text": "Vascular phenomena count as minor criteria."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Minor criteria include predisposition, fever >38°C, vascular phenomena, immunologic phenomena, and microbiologic evidence not meeting major.', 'Infective Endocarditis - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Definite diagnosis combinations rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Definite diagnosis combinations rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Three minor criteria alone are definitive in this note."}, {"id": "b", "text": "One major alone is always definitive in this note."}, {"id": "c", "text": "Two major criteria can establish definite diagnosis."}, {"id": "d", "text": "Five minor criteria can establish diagnosis."}, {"id": "e", "text": "One major plus three minor can establish diagnosis."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Definite diagnosis is 2 major OR 1 major + 3 minor OR 5 minor criteria.', 'Infective Endocarditis - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Blood culture protocol? (Select all that apply)', 'During reassessment, which observations align with Blood culture protocol? (Select all that apply)', '[{"id": "a", "text": "Three culture sets are recommended in this note."}, {"id": "b", "text": "Antibiotics should start before any cultures in this note."}, {"id": "c", "text": "Different collection sites are required."}, {"id": "d", "text": "Only one blood culture is needed in this note."}, {"id": "e", "text": "Cultures should be drawn before antibiotics."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Obtain blood cultures ×3 from different sites before starting antibiotics.', 'Infective Endocarditis - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Echo sensitivity. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Echo sensitivity. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Echo has no role in diagnosis in this note."}, {"id": "b", "text": "TEE is more sensitive than TTE in this note."}, {"id": "c", "text": "Vegetation detection is central to diagnosis."}, {"id": "d", "text": "TTE is always more sensitive than TEE in this note."}, {"id": "e", "text": "Echo evaluates endocardial involvement."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: TEE is more sensitive than TTE for detecting vegetations.', 'Infective Endocarditis - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Lab trends, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Lab trends, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Leukocytosis is listed in workup."}, {"id": "b", "text": "Inflammatory markers are always normal in this note."}, {"id": "c", "text": "Hematuria may suggest renal embolic involvement."}, {"id": "d", "text": "Hematuria excludes endocarditis in this note."}, {"id": "e", "text": "ESR/CRP elevation is listed in workup."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: CBC can show leukocytosis, ESR/CRP can be elevated, and urinalysis can show hematuria from renal emboli.', 'Infective Endocarditis - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Antibiotic duration. Which items should be included? (Select all that apply)', 'The nurse plans care around Antibiotic duration. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "No culture follow-up is needed after therapy starts in this note."}, {"id": "b", "text": "IV treatment is typically 4–6 weeks."}, {"id": "c", "text": "A 3-day oral course is adequate in this note."}, {"id": "d", "text": "Culture clearance monitoring is required."}, {"id": "e", "text": "Regimen depends on organism type."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Treatment requires IV antibiotics for 4–6 weeks with organism-specific regimens and culture-confirmed clearance.', 'Infective Endocarditis - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Organism-specific regimens rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Organism-specific regimens rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Enterococcus regimen includes ampicillin + gentamicin."}, {"id": "b", "text": "Enterococcus is treated with no antibiotics in this note."}, {"id": "c", "text": "MRSA coverage can require vancomycin."}, {"id": "d", "text": "MRSA is first-line treated with amoxicillin alone in this note."}, {"id": "e", "text": "Strep regimens include penicillin or ampicillin."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Examples listed: strep with penicillin/ampicillin, staph with nafcillin or vancomycin for MRSA, enterococcus with ampicillin plus gentamicin.', 'Infective Endocarditis - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Surgical indications? (Select all that apply)', 'During reassessment, which observations align with Surgical indications? (Select all that apply)', '[{"id": "a", "text": "Vegetation >10 mm with embolic risk is an indication."}, {"id": "b", "text": "Severe regurgitation from valve destruction is an indication."}, {"id": "c", "text": "All cases should avoid surgery regardless of deterioration in this note."}, {"id": "d", "text": "Fungal endocarditis is never surgical in this note."}, {"id": "e", "text": "Uncontrolled infection despite antibiotics is an indication."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Surgery is indicated for severe regurgitation from valve destruction, uncontrolled infection, vegetation >10 mm with embolic risk, prosthetic valve infection, or fungal endocarditis.', 'Infective Endocarditis - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Nursing priorities. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Nursing priorities. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "New murmur assessment is emphasized."}, {"id": "b", "text": "Fever monitoring is emphasized."}, {"id": "c", "text": "Short peripheral IV rotation is preferred over stable long-term access in this note."}, {"id": "d", "text": "Murmur reassessment is unnecessary in this note."}, {"id": "e", "text": "Long-term IV access maintenance is emphasized."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Nursing priorities include cultures before antibiotics, fever monitoring, new murmur assessment, embolic surveillance, and long-term IV access care.', 'Infective Endocarditis - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected infective endocarditis and Prophylaxis, which statements are correct? (Select all that apply)', 'For suspected infective endocarditis and Prophylaxis, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Dental prophylaxis is unnecessary in high-risk patients in this note."}, {"id": "b", "text": "Prophylaxis is only after procedures in this note."}, {"id": "c", "text": "Amoxicillin is the prophylactic example provided."}, {"id": "d", "text": "Prevention targets bacteremia-triggered endocarditis."}, {"id": "e", "text": "Dental prophylaxis is listed for high-risk groups."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: High-risk patients should receive amoxicillin prophylaxis before dental procedures.', 'Infective Endocarditis - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around NCLEX synthesis. Which items should be included? (Select all that apply)', 'The nurse plans care around NCLEX synthesis. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Embolic signs lower IE suspicion in this note."}, {"id": "b", "text": "Positive cultures strengthen urgency."}, {"id": "c", "text": "Fever plus new murmur is a key cluster."}, {"id": "d", "text": "Embolic signs increase concern for active IE."}, {"id": "e", "text": "Culture positivity should delay treatment in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: High-yield pattern: fever + new regurgitant murmur + positive cultures + embolic signs should trigger urgent IE workup and treatment.', 'Infective Endocarditis - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which findings support Definition rather than an alternative diagnosis? (Select all that apply)', 'Which findings support Definition rather than an alternative diagnosis? (Select all that apply)', '[{"id": "a", "text": "Endocarditis is infection of the pericardium in this note."}, {"id": "b", "text": "Vegetations in this note are sterile in infective cases."}, {"id": "c", "text": "Vegetations include fibrin, platelets, and microorganisms."}, {"id": "d", "text": "Endocarditis affects the inner lining and valves."}, {"id": "e", "text": "Valve involvement is a central feature."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Infective endocarditis is infection of the endocardium, especially heart valves, with vegetations made of fibrin, platelets, and organisms.', 'Infective Endocarditis - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations align with Valve distribution? (Select all that apply)', 'During reassessment, which observations align with Valve distribution? (Select all that apply)', '[{"id": "a", "text": "Valve choice is random and unrelated to risk factors in this note."}, {"id": "b", "text": "IV drug use is primarily linked to left-sided mitral lesions in this note."}, {"id": "c", "text": "IV drug use is linked to right-sided (tricuspid) disease."}, {"id": "d", "text": "Mitral valve involvement is common in this note."}, {"id": "e", "text": "Valve pattern can reflect exposure risks."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Mitral valve is commonly affected on the left side, and tricuspid involvement is common in IV drug use (right-sided).', 'Infective Endocarditis - NCLEX', true, 100, 1, true);
END $$;
COMMIT;